<?php
namespace App\Jobs;
use App\Enums\PrintOrderStatus; use App\Models\PrintOrder; use App\Services\Esp32DeviceService; use App\Services\LockerAssignmentService; use App\Services\OrderStatusService; use Illuminate\Contracts\Queue\ShouldQueue; use Illuminate\Foundation\Queue\Queueable;
class ClosePickupLockerJob implements ShouldQueue { use Queueable; public function __construct(public int $orderId){} public function handle(Esp32DeviceService $device,OrderStatusService $statuses,LockerAssignmentService $lockers):void{$order=PrintOrder::findOrFail($this->orderId);if($order->status!==PrintOrderStatus::OpeningLocker)return;$device->closePickupDoor($order);$statuses->transition($order,PrintOrderStatus::Claimed,'Document collected.',['claimed_at'=>now()]);$lockers->release($order);$device->setLockerAvailable($order);} }
